# backend/tests/test_ascii_smuggling_boundaries.py
#
# Regression coverage for deterministic ASCII-smuggling removal at LLM
# boundaries. These tests use the same Unicode Tags payload generated by
# public ASCII Smuggler tools and ensure it cannot reach model-visible text.
#
# Architecture: docs/architecture/privacy/prompt-injection.md

